<?php
require __DIR__.'/../includes/bootstrap.php';require_auth();if(!companies_schema_ready())redirect('../dashboard.php');$id=(int)($_GET['id']??0);$s=db()->prepare('SELECT * FROM companies WHERE id=?');$s->execute([$id]);$c=$s->fetch();if(!$c){http_response_code(404);exit('Company not found.');}$membership=company_member_for_user($id,(int)user()['id']);if(!$membership&&(user()['role']??'')!=='admin'){http_response_code(403);exit('You do not have access to this company.');}
app_header($c['name'].' Dashboard');
?><section class="dashboard-hero"><p class="eyebrow">COMPANY DASHBOARD</p><h1><?=e($c['name'])?></h1><p><span class="status-badge <?=e($c['status'])?>"><?=e(ucfirst($c['status']))?></span></p></section><section class="dashboard-grid"><article class="app-card"><h2>Approval</h2><p><strong>Status:</strong> <?=e(ucfirst($c['status']))?></p><?php if($c['status']==='pending'):?><p class="muted">An administrator is reviewing this company. It is not public yet.</p><?php elseif($c['status']==='rejected'):?><p><?=nl2br(e($c['review_notes']?:'The submission needs changes.'))?></p><?php endif?></article><article class="app-card"><h2>Your Relationship</h2><p><strong><?=e(ucwords(str_replace('_',' ',$membership['relationship_type']??'Administrator')))?></strong></p><?php if(!empty($membership['position_title'])):?><p><?=e($membership['position_title'])?></p><?php endif?><p class="muted"><?=e(ucwords(str_replace('_',' ',$membership['company_role']??'platform administrator')))?></p></article><article class="app-card"><h2>Company Profile</h2><p><?=e($c['short_description']?:'No short description yet.')?></p><p><?php if($c['status']==='approved'):?><a class="button primary" href="view.php?slug=<?=urlencode($c['slug'])?>">View Public Profile</a><?php endif?> <?php if(can_manage_company($c)):?><a class="button ghost" href="edit.php?id=<?=$id?>">Edit Company</a><?php endif?></p></article></section><?php app_footer();
